code_changes.content:
[
  {
    "file": "src/vs/base/common/strings.ts",
    "line": 215,
    "severity": "high",
    "description": "createRegExp's wholeWord handling uses incorrect logic to detect existing word boundaries. It tests if a single character matches the regex /\\B/, which will never work as intended. The code checks `!/\\B/.test(searchString.charAt(0))` to decide whether to prepend \\b, but a single character cannot match a two-character pattern (backslash + B). This breaks whole-word regex construction for strings that already contain backslashes, resulting in malformed regex patterns with duplicate boundary markers.",
    "fix_patch": "--- a/src/vs/base/common/strings.ts
+++ b/src/vs/base/common/strings.ts
@@ -212,14 +212,14 @@ export function createRegExp(searchString: string, isRegex: boolean, options: R
 	}
 	if (options.wholeWord) {
-		if (!/\\B/.test(searchString.charAt(0))) {
+		if (!searchString.startsWith('\\b')) {
 			searchString = '\\b' + searchString;
 		}
-		if (!/\\B/.test(searchString.charAt(searchString.length - 1))) {
+		if (!searchString.endsWith('\\b')) {
 			searchString = searchString + '\\b';
 		}
 	}
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 92,
    "severity": "medium",
    "description": "isMultilineRegexSource detects multiline regex patterns by checking for escape sequences, but incorrectly includes CharCode.W (uppercase). The 'W' character class (\W for non-word characters) is not a multiline indicator. The \\n and \\r checks are correct for detecting newline patterns, but \W is unrelated to multiline matching. This causes false positives when searching for patterns containing \W, incorrectly treating them as multiline regex sources.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -89,7 +89,7 @@ export function isMultilineRegexSource(searchString: string): boolean {
 		}

 		const nextChCode = searchString.charCodeAt(i);
-		if (nextChCode === CharCode.n || nextChCode === CharCode.r || nextChCode === CharCode.W) {
+		if (nextChCode === CharCode.n || nextChCode === CharCode.r) {
 			return true;
 		}
 	}
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 450,
    "severity": "high",
    "description": "leftIsWordBounday contains invalid logic that checks if the first character of the match is NOT a regular word character and returns true. This is semantically incorrect for boundary detection. A word boundary should be determined by what's OUTSIDE the match (the character before the match), not by what's INSIDE. This causes whole-word matching to incorrectly validate matches that start with word separators (like punctuation patterns), violating the whole-word contract.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -446,13 +446,6 @@ function leftIsWordBounday(wordSeparators: WordCharacterClassifier, text: strin
 		return true;
 	}

-	if (matchLength > 0) {
-		const firstCharInMatch = text.charCodeAt(matchStartIndex);
-		if (wordSeparators.get(firstCharInMatch) !== WordCharacterClass.Regular) {
-			return true;
-		}
-	}
-
 	return false;
 }
"
  },
  {
    "file": "src/vs/editor/common/model/textModelSearch.ts",
    "line": 478,
    "severity": "high",
    "description": "rightIsWordBounday contains the same invalid boundary logic as leftIsWordBounday. It checks if the last character of the match is NOT a regular word character and returns true, which is incorrect. Word boundaries should be determined by what's outside the match (the character after), not inside. This allows matches ending with separators to incorrectly validate as whole-word matches.",
    "fix_patch": "--- a/src/vs/editor/common/model/textModelSearch.ts
+++ b/src/vs/editor/common/model/textModelSearch.ts
@@ -474,13 +474,6 @@ function rightIsWordBounday(wordSeparators: WordCharacterClassifier, text: stri
 		return true;
 	}

-	if (matchLength > 0) {
-		const lastCharInMatch = text.charCodeAt(matchStartIndex + matchLength - 1);
-		if (wordSeparators.get(lastCharInMatch) !== WordCharacterClass.Regular) {
-			return true;
-		}
-	}
-
 	return false;
 }
"
  }
]

